module counter_4bit(
    input               clk,
    input               rst,
    input               en,
    output reg [3:0]    q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst)
        q <= 4'd0;
    else if (en)
        q <= q + 1;
end

endmodule
